// Inside a Workflow script — the pr-reviewer skill is already registered
const FILES = ['src/auth.ts', 'src/api/users.ts', 'src/db/queries.ts']

const FINDINGS_SCHEMA = {
  type: 'object',
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          file: { type: 'string' },
          line: { type: 'number' },
          severity: { type: 'string', enum: ['high', 'medium', 'low'] },
          summary: { type: 'string' },
          failure_scenario: { type: 'string' }
        },
        required: ['file', 'line', 'severity', 'summary', 'failure_scenario']
      }
    }
  }
}

// Fan out one pr-reviewer agent per file in parallel
const results = await parallel(
  FILES.map(file => () =>
    agent(
      `Review ${file} for correctness, security, and simplification opportunities.`,
      {
        label: `review:${file}`,
        agentType: 'pr-reviewer',   // references the skill by name
        schema: FINDINGS_SCHEMA
      }
    )
  )
)

const allFindings = results
  .filter(Boolean)
  .flatMap(r => r.findings)
  .sort((a, b) => { const s = {high:0,medium:1,low:2}; return s[a.severity] - s[b.severity] })

return { findings: allFindings }
